import { useEffect, useMemo, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

import { apiClient, authService } from "@/App";
import { toast } from "sonner";

import {
  Plus,
  BookOpen,
  Users,
  ClipboardList,
  Award,
  TrendingUp,
  Download,
  Eye,
  Search,
  Phone,
  Mail,
} from "lucide-react";

import jsPDF from "jspdf";

const CBE_GRADES = [
  { value: "EE", label: "EE - Exceeding Expectations", min: 80 },
  { value: "ME", label: "ME - Meeting Expectations", min: 60 },
  { value: "AE", label: "AE - Approaching Expectations", min: 40 },
  { value: "BE", label: "BE - Below Expectations", min: 0 },
];

const calculateCBEGrade = (marks) => {
  if (marks >= 80) return "EE";
  if (marks >= 60) return "ME";
  if (marks >= 40) return "AE";
  return "BE";
};

const gradeColor = (grade) => {
  switch (grade) {
    case "EE":
      return "bg-green-100 text-green-800 border-green-200";
    case "ME":
      return "bg-blue-100 text-blue-800 border-blue-200";
    case "AE":
      return "bg-yellow-100 text-yellow-800 border-yellow-200";
    default:
      return "bg-red-100 text-red-800 border-red-200";
  }
};

const approvalColor = (status) => {
  switch (status) {
    case "approved":
      return "bg-green-100 text-green-800";
    case "rejected":
      return "bg-red-100 text-red-800";
    default:
      return "bg-yellow-100 text-yellow-800";
  }
};

const attendanceColor = (status) => {
  switch (status) {
    case "present":
      return "bg-green-100 text-green-800";
    case "absent":
      return "bg-red-100 text-red-800";
    case "late":
      return "bg-yellow-100 text-yellow-800";
    default:
      return "bg-blue-100 text-blue-800";
  }
};

const TeacherPortal = () => {
  const user = authService.getUser();

  const [students, setStudents] = useState([]);
  const [exams, setExams] = useState([]);
  const [attendance, setAttendance] = useState([]);

  const [loading, setLoading] = useState(true);

  const [selectedClass, setSelectedClass] = useState("all");
  const [searchTerm, setSearchTerm] = useState("");

  const [resultsDialogOpen, setResultsDialogOpen] = useState(false);
  const [attendanceDialogOpen, setAttendanceDialogOpen] = useState(false);
  const [progressDialogOpen, setProgressDialogOpen] = useState(false);

  const [selectedStudent, setSelectedStudent] = useState(null);
  const [studentResults, setStudentResults] = useState([]);

  const [resultForm, setResultForm] = useState({
    exam_id: "",
    student_id: "",
    subject: "",
    marks: "",
    grade: "",
    teacher_comments: "",
  });

  const [attendanceForm, setAttendanceForm] = useState({
    student_id: "",
    date: new Date().toISOString().split("T")[0],
    status: "present",
    remarks: "",
  });

  useEffect(() => {
    fetchTeacherData();
  }, []);

  const fetchTeacherData = async () => {
    try {
      setLoading(true);

      const [studentsRes, examsRes, attendanceRes] = await Promise.all([
        apiClient.get("/students?approval_status=all"),
        apiClient.get("/exams"),
        apiClient.get("/attendance?approval_status=all"),
      ]);

      setStudents(studentsRes.data || []);
      setExams(examsRes.data || []);
      setAttendance(attendanceRes.data || []);
    } catch (error) {
      toast.error("Failed to fetch teacher portal data");
    } finally {
      setLoading(false);
    }
  };

  const myClasses = useMemo(() => {
    return [
      ...new Set(
        students
          .map((s) => s.class_name || s.year_of_study)
          .filter(Boolean)
      ),
    ];
  }, [students]);

  const filteredStudents = useMemo(() => {
    return students.filter((student) => {
      const classValue =
        student.class_name || student.year_of_study || "";

      const matchesClass =
        selectedClass === "all" || classValue === selectedClass;

      const matchesSearch =
        student.full_name
          ?.toLowerCase()
          .includes(searchTerm.toLowerCase()) ||
        student.admission_number
          ?.toLowerCase()
          .includes(searchTerm.toLowerCase());

      return matchesClass && matchesSearch;
    });
  }, [students, selectedClass, searchTerm]);

  const todayAttendance = attendance.filter(
    (a) => a.date === new Date().toISOString().split("T")[0]
  ).length;

  const handleSubmitResult = async (e) => {
    e.preventDefault();

    try {
      const payload = {
        ...resultForm,
        marks: Number(resultForm.marks),
        max_marks: 100,
      };

      const response = await apiClient.post("/results", payload);

      toast.success(
        response.data.approval_status === "pending"
          ? "Result submitted for approval"
          : "Result recorded successfully"
      );

      setResultsDialogOpen(false);

      setResultForm({
        exam_id: "",
        student_id: "",
        subject: "",
        marks: "",
        grade: "",
        teacher_comments: "",
      });

      fetchTeacherData();
    } catch (error) {
      toast.error(
        error.response?.data?.detail || "Failed to record result"
      );
    }
  };

  const handleMarkAttendance = async (e) => {
    e.preventDefault();

    try {
      const response = await apiClient.post("/attendance", {
        entity_type: "student",
        entity_id: attendanceForm.student_id,
        date: attendanceForm.date,
        status: attendanceForm.status,
        remarks: attendanceForm.remarks,
      });

      toast.success(
        response.data.approval_status === "pending"
          ? "Attendance submitted for approval"
          : "Attendance marked successfully"
      );

      setAttendanceDialogOpen(false);

      setAttendanceForm({
        student_id: "",
        date: new Date().toISOString().split("T")[0],
        status: "present",
        remarks: "",
      });

      fetchTeacherData();
    } catch (error) {
      toast.error(
        error.response?.data?.detail || "Failed to mark attendance"
      );
    }
  };

  const viewStudentProgress = async (student) => {
    setSelectedStudent(student);

    try {
      const response = await apiClient.get(`/results/${student.id}`);
      setStudentResults(response.data || []);
    } catch (error) {
      setStudentResults([]);
    }

    setProgressDialogOpen(true);
  };

  const generateClassReport = () => {
    const doc = new jsPDF();

    doc.setFontSize(20);
    doc.text("Class Performance Report (CBE)", 20, 20);

    doc.setFontSize(12);
    doc.text(`Teacher: ${user?.full_name || "Teacher"}`, 20, 35);
    doc.text(
      `Generated: ${new Date().toLocaleDateString()}`,
      20,
      45
    );

    let y = 65;

    filteredStudents.forEach((student, index) => {
      doc.text(
        `${index + 1}. ${student.full_name} - ${
          student.class_name || student.year_of_study || "-"
        }`,
        20,
        y
      );

      y += 10;

      if (y > 270) {
        doc.addPage();
        y = 20;
      }
    });

    doc.save(`class-report-${Date.now()}.pdf`);

    toast.success("Class report downloaded");
  };

  return (
    <div className="space-y-6" data-testid="teacher-portal">
      {/* HEADER */}
      <div className="bg-gradient-to-r from-emerald-600/20 to-teal-600/20 border border-emerald-500/20 rounded-2xl p-8">
        <h2 className="text-4xl font-bold text-white">
          Teacher Portal
        </h2>

        <p className="text-emerald-300/70 mt-2 text-lg">
          Welcome back, {user?.full_name}
        </p>

        <p className="text-emerald-400/50 text-sm mt-1">
          CBC/CBE Grading: EE | ME | AE | BE
        </p>
      </div>

      {/* STATS */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <Card className="border-l-4 border-l-emerald-500 bg-[#1A2332] border-[#1E293B]">
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between">
              <CardTitle className="text-sm text-slate-400">
                My Classes
              </CardTitle>

              <BookOpen className="w-5 h-5 text-emerald-400" />
            </div>
          </CardHeader>

          <CardContent>
            <div className="text-3xl font-bold text-white">
              {myClasses.length}
            </div>
          </CardContent>
        </Card>

        <Card className="border-l-4 border-l-blue-500 bg-[#1A2332] border-[#1E293B]">
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between">
              <CardTitle className="text-sm text-slate-400">
                Total Students
              </CardTitle>

              <Users className="w-5 h-5 text-blue-400" />
            </div>
          </CardHeader>

          <CardContent>
            <div className="text-3xl font-bold text-white">
              {students.length}
            </div>
          </CardContent>
        </Card>

        <Card className="border-l-4 border-l-purple-500 bg-[#1A2332] border-[#1E293B]">
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between">
              <CardTitle className="text-sm text-slate-400">
                Today's Attendance
              </CardTitle>

              <ClipboardList className="w-5 h-5 text-purple-400" />
            </div>
          </CardHeader>

          <CardContent>
            <div className="text-3xl font-bold text-white">
              {todayAttendance}
            </div>
          </CardContent>
        </Card>

        <Card className="border-l-4 border-l-orange-500 bg-[#1A2332] border-[#1E293B]">
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between">
              <CardTitle className="text-sm text-slate-400">
                Active Exams
              </CardTitle>

              <Award className="w-5 h-5 text-orange-400" />
            </div>
          </CardHeader>

          <CardContent>
            <div className="text-3xl font-bold text-white">
              {exams.length}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* TABS */}
      <Tabs defaultValue="students" className="space-y-6">
        <TabsList className="bg-slate-100">
          <TabsTrigger value="students">My Students</TabsTrigger>
          <TabsTrigger value="results">Record Results</TabsTrigger>
          <TabsTrigger value="attendance">
            Mark Attendance
          </TabsTrigger>
          <TabsTrigger value="performance">
            Performance
          </TabsTrigger>
        </TabsList>

        {/* STUDENTS TAB */}
        <TabsContent value="students">
          <Card>
            <CardHeader>
              <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4">
                <CardTitle>Class Students</CardTitle>

                <div className="flex flex-col md:flex-row gap-3">
                  <div className="relative">
                    <Search className="absolute left-3 top-3 h-4 w-4 text-slate-400" />

                    <Input
                      placeholder="Search students..."
                      value={searchTerm}
                      onChange={(e) =>
                        setSearchTerm(e.target.value)
                      }
                      className="pl-10 w-full md:w-64"
                    />
                  </div>

                  <Select
                    value={selectedClass}
                    onValueChange={setSelectedClass}
                  >
                    <SelectTrigger className="w-full md:w-48">
                      <SelectValue placeholder="All Classes" />
                    </SelectTrigger>

                    <SelectContent>
                      <SelectItem value="all">
                        All Classes
                      </SelectItem>

                      {myClasses.map((cls) => (
                        <SelectItem key={cls} value={cls}>
                          {cls}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>

                  <Button
                    variant="outline"
                    onClick={generateClassReport}
                  >
                    <Download className="w-4 h-4 mr-2" />
                    Export PDF
                  </Button>
                </div>
              </div>
            </CardHeader>

            <CardContent>
              {loading ? (
                <div className="text-center py-10">
                  Loading students...
                </div>
              ) : filteredStudents.length === 0 ? (
                <div className="text-center py-10 text-slate-500">
                  No students found
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {filteredStudents.map((student) => (
                    <div
                      key={student.id}
                      className="p-5 border rounded-xl bg-white shadow-sm hover:shadow-md transition"
                    >
                      <div className="flex items-start justify-between">
                        <div>
                          <h3 className="font-bold text-lg text-slate-900">
                            {student.full_name}
                          </h3>

                          <p className="text-sm text-slate-500">
                            {student.admission_number}
                          </p>

                          <Badge className="mt-2 bg-emerald-100 text-emerald-700">
                            {student.class_name ||
                              student.year_of_study}
                          </Badge>
                        </div>

                        <TrendingUp className="w-5 h-5 text-emerald-500" />
                      </div>

                      <div className="mt-4 space-y-2 text-sm text-slate-600">
                        <div className="flex items-center gap-2">
                          <Phone className="w-4 h-4" />
                          {student.guardian_phone || "No phone"}
                        </div>

                        <div className="flex items-center gap-2">
                          <Mail className="w-4 h-4" />
                          {student.guardian_email || "No email"}
                        </div>
                      </div>

                      <div className="mt-4 pt-4 border-t flex gap-2">
                        <Button
                          size="sm"
                          variant="outline"
                          className="flex-1"
                          onClick={() =>
                            viewStudentProgress(student)
                          }
                        >
                          <Eye className="w-4 h-4 mr-1" />
                          View Progress
                        </Button>

                        <Button
                          size="sm"
                          className="flex-1 bg-emerald-600 hover:bg-emerald-700"
                        >
                          Contact Parent
                        </Button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        {/* RESULTS TAB */}
        <TabsContent value="results">
          <Card>
            <CardHeader>
              <div className="flex items-center justify-between">
                <div>
                  <CardTitle>
                    Record Exam Results (CBE)
                  </CardTitle>

                  <p className="text-sm text-slate-500 mt-1">
                    Use EE, ME, AE and BE grading system
                  </p>
                </div>

                <Dialog
                  open={resultsDialogOpen}
                  onOpenChange={setResultsDialogOpen}
                >
                  <DialogTrigger asChild>
                    <Button className="bg-blue-600 hover:bg-blue-700">
                      <Plus className="w-4 h-4 mr-2" />
                      Add Result
                    </Button>
                  </DialogTrigger>

                  <DialogContent>
                    <DialogHeader>
                      <DialogTitle>
                        Record Student Result
                      </DialogTitle>
                    </DialogHeader>

                    <form
                      onSubmit={handleSubmitResult}
                      className="space-y-4"
                    >
                      <div className="space-y-2">
                        <Label>Exam *</Label>

                        <Select
                          value={resultForm.exam_id}
                          onValueChange={(v) =>
                            setResultForm({
                              ...resultForm,
                              exam_id: v,
                            })
                          }
                        >
                          <SelectTrigger>
                            <SelectValue placeholder="Select exam" />
                          </SelectTrigger>

                          <SelectContent>
                            {exams.map((exam) => (
                              <SelectItem
                                key={exam.id}
                                value={exam.id}
                              >
                                {exam.name}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                      </div>

                      <div className="space-y-2">
                        <Label>Student *</Label>

                        <Select
                          value={resultForm.student_id}
                          onValueChange={(v) =>
                            setResultForm({
                              ...resultForm,
                              student_id: v,
                            })
                          }
                        >
                          <SelectTrigger>
                            <SelectValue placeholder="Select student" />
                          </SelectTrigger>

                          <SelectContent>
                            {students.map((student) => (
                              <SelectItem
                                key={student.id}
                                value={student.id}
                              >
                                {student.full_name} -{" "}
                                {student.admission_number}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                      </div>

                      <div className="space-y-2">
                        <Label>Subject *</Label>

                        <Input
                          value={resultForm.subject}
                          onChange={(e) =>
                            setResultForm({
                              ...resultForm,
                              subject: e.target.value,
                            })
                          }
                          required
                        />
                      </div>

                      <div className="space-y-2">
                        <Label>Marks *</Label>

                        <Input
                          type="number"
                          min="0"
                          max="100"
                          value={resultForm.marks}
                          onChange={(e) => {
                            const value = e.target.value;

                            setResultForm({
                              ...resultForm,
                              marks: value,
                              grade: value
                                ? calculateCBEGrade(
                                    parseFloat(value)
                                  )
                                : "",
                            });
                          }}
                          required
                        />
                      </div>

                      <div className="space-y-2">
                        <Label>Grade</Label>

                        <div className="flex items-center gap-2">
                          <Input
                            value={resultForm.grade}
                            readOnly
                            className="bg-slate-100"
                          />

                          {resultForm.grade && (
                            <Badge
                              className={gradeColor(
                                resultForm.grade
                              )}
                            >
                              {resultForm.grade}
                            </Badge>
                          )}
                        </div>
                      </div>

                      <div className="space-y-2">
                        <Label>Teacher Comments</Label>

                        <Textarea
                          rows={3}
                          value={resultForm.teacher_comments}
                          onChange={(e) =>
                            setResultForm({
                              ...resultForm,
                              teacher_comments:
                                e.target.value,
                            })
                          }
                          placeholder="Enter comments..."
                        />
                      </div>

                      <Button
                        type="submit"
                        className="w-full bg-emerald-600 hover:bg-emerald-700"
                      >
                        Submit Result
                      </Button>
                    </form>
                  </DialogContent>
                </Dialog>
              </div>
            </CardHeader>

            <CardContent>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {CBE_GRADES.map((grade) => (
                  <div
                    key={grade.value}
                    className="border rounded-xl p-4 text-center"
                  >
                    <Badge
                      className={`${gradeColor(
                        grade.value
                      )} text-base px-3 py-1`}
                    >
                      {grade.value}
                    </Badge>

                    <p className="mt-2 text-sm text-slate-600">
                      {grade.label.split(" - ")[1]}
                    </p>

                    <p className="text-xs text-slate-400 mt-1">
                      {grade.min}%+
                    </p>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        {/* ATTENDANCE TAB */}
        <TabsContent value="attendance">
          <Card>
            <CardHeader>
              <div className="flex items-center justify-between">
                <CardTitle>
                  Mark Student Attendance
                </CardTitle>

                <Dialog
                  open={attendanceDialogOpen}
                  onOpenChange={setAttendanceDialogOpen}
                >
                  <DialogTrigger asChild>
                    <Button className="bg-purple-600 hover:bg-purple-700">
                      <Plus className="w-4 h-4 mr-2" />
                      Mark Attendance
                    </Button>
                  </DialogTrigger>

                  <DialogContent>
                    <DialogHeader>
                      <DialogTitle>
                        Mark Attendance
                      </DialogTitle>
                    </DialogHeader>

                    <form
                      onSubmit={handleMarkAttendance}
                      className="space-y-4"
                    >
                      <div className="space-y-2">
                        <Label>Date *</Label>

                        <Input
                          type="date"
                          value={attendanceForm.date}
                          onChange={(e) =>
                            setAttendanceForm({
                              ...attendanceForm,
                              date: e.target.value,
                            })
                          }
                          required
                        />
                      </div>

                      <div className="space-y-2">
                        <Label>Student *</Label>

                        <Select
                          value={attendanceForm.student_id}
                          onValueChange={(v) =>
                            setAttendanceForm({
                              ...attendanceForm,
                              student_id: v,
                            })
                          }
                        >
                          <SelectTrigger>
                            <SelectValue placeholder="Select student" />
                          </SelectTrigger>

                          <SelectContent>
                            {students.map((student) => (
                              <SelectItem
                                key={student.id}
                                value={student.id}
                              >
                                {student.full_name}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                      </div>

                      <div className="space-y-2">
                        <Label>Status *</Label>

                        <Select
                          value={attendanceForm.status}
                          onValueChange={(v) =>
                            setAttendanceForm({
                              ...attendanceForm,
                              status: v,
                            })
                          }
                        >
                          <SelectTrigger>
                            <SelectValue />
                          </SelectTrigger>

                          <SelectContent>
                            <SelectItem value="present">
                              Present
                            </SelectItem>

                            <SelectItem value="absent">
                              Absent
                            </SelectItem>

                            <SelectItem value="late">
                              Late
                            </SelectItem>

                            <SelectItem value="excused">
                              Excused
                            </SelectItem>
                          </SelectContent>
                        </Select>
                      </div>

                      <div className="space-y-2">
                        <Label>Remarks</Label>

                        <Textarea
                          rows={2}
                          value={attendanceForm.remarks}
                          onChange={(e) =>
                            setAttendanceForm({
                              ...attendanceForm,
                              remarks: e.target.value,
                            })
                          }
                        />
                      </div>

                      <Button
                        type="submit"
                        className="w-full bg-emerald-600 hover:bg-emerald-700"
                      >
                        Submit Attendance
                      </Button>
                    </form>
                  </DialogContent>
                </Dialog>
              </div>
            </CardHeader>

            <CardContent>
              {attendance.length === 0 ? (
                <div className="text-center py-12 text-slate-500">
                  No attendance records found
                </div>
              ) : (
                <div className="overflow-auto rounded-lg border">
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Date</TableHead>
                        <TableHead>Status</TableHead>
                        <TableHead>Remarks</TableHead>
                        <TableHead>Approval</TableHead>
                      </TableRow>
                    </TableHeader>

                    <TableBody>
                      {attendance.slice(0, 20).map((a) => (
                        <TableRow key={a.id}>
                          <TableCell>{a.date}</TableCell>

                          <TableCell>
                            <Badge
                              className={attendanceColor(
                                a.status
                              )}
                            >
                              {a.status}
                            </Badge>
                          </TableCell>

                          <TableCell>
                            {a.remarks || "-"}
                          </TableCell>

                          <TableCell>
                            <Badge
                              className={approvalColor(
                                a.approval_status
                              )}
                            >
                              {a.approval_status}
                            </Badge>
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        {/* PERFORMANCE TAB */}
        <TabsContent value="performance">
          <Card>
            <CardHeader>
              <CardTitle>
                Class Performance Analytics
              </CardTitle>
            </CardHeader>

            <CardContent>
              <div className="text-center py-12 text-slate-500">
                <TrendingUp className="w-16 h-16 mx-auto mb-4 text-slate-400" />

                <p className="text-lg font-medium">
                  Performance analytics coming soon
                </p>

                <p className="text-sm mt-2">
                  CBC/CBE student tracking dashboard
                </p>
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* STUDENT PROGRESS DIALOG */}
      <Dialog
        open={progressDialogOpen}
        onOpenChange={setProgressDialogOpen}
      >
        <DialogContent className="max-w-3xl">
          <DialogHeader>
            <DialogTitle>
              Student Progress -{" "}
              {selectedStudent?.full_name}
            </DialogTitle>
          </DialogHeader>

          <div className="space-y-4">
            {selectedStudent && (
              <div className="p-4 rounded-lg bg-slate-50 border">
                <p className="text-sm">
                  <span className="font-medium">
                    Admission Number:
                  </span>{" "}
                  {selectedStudent.admission_number}
                </p>

                <p className="text-sm mt-1">
                  <span className="font-medium">
                    Class:
                  </span>{" "}
                  {selectedStudent.class_name ||
                    selectedStudent.year_of_study}
                </p>
              </div>
            )}

            {studentResults.length === 0 ? (
              <div className="text-center py-10 text-slate-500">
                No results recorded yet
              </div>
            ) : (
              <div className="overflow-auto rounded-lg border">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Subject</TableHead>
                      <TableHead>Marks</TableHead>
                      <TableHead>Grade</TableHead>
                      <TableHead>Comments</TableHead>
                      <TableHead>Status</TableHead>
                    </TableRow>
                  </TableHeader>

                  <TableBody>
                    {studentResults.map((result) => (
                      <TableRow key={result.id}>
                        <TableCell className="font-medium">
                          {result.subject}
                        </TableCell>

                        <TableCell>
                          {result.marks}/
                          {result.max_marks || 100}
                        </TableCell>

                        <TableCell>
                          <Badge
                            className={gradeColor(
                              result.grade
                            )}
                          >
                            {result.grade}
                          </Badge>
                        </TableCell>

                        <TableCell>
                          {result.teacher_comments || "-"}
                        </TableCell>

                        <TableCell>
                          <Badge
                            className={approvalColor(
                              result.approval_status
                            )}
                          >
                            {result.approval_status}
                          </Badge>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </div>
            )}
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default TeacherPortal;
